<template>
  <div>
    <!-- 表头 -->
    <van-nav-bar title="设置密码" left-text="">
      <template #right>
        <span class="zqd_sp1">跳过</span>
      </template>
    </van-nav-bar>
    <!-- input  -->
    <!-- <div class="zqd_div" :class="input1 ? 'zqd_active' : ''"> -->
      <!-- <van-field center clearable label="" placeholder="请输入手机号" @focus="input1 = true" @blur="input1 = false">
        <template #button>
          <span @click="zqd_fa" v-show="zqd_show">获取验证码</span>

          <p @click="zqd_fa" id="qq" v-show="!zqd_show"><van-count-down :time="60*1000" format="获取验证码 (ss)" /></p>
        </template>
      </van-field> -->
    <!-- </div> -->
    <div class="zqd_div" :class="a ? 'zqd_active' : ''">
      <input type="text" placeholder="请设置登录密码" @focus="a = true" @blur="a = false" v-model="text1"/>
    </div>
    <div class="zqd_div" :class="b ? 'zqd_active' : ''">
      <input type="text" placeholder="请再次输入密码" @focus="b = true" @blur="b = false"  v-model="text2"/>
    </div>

    <van-button type="primary" id="zqd" @click="zqd_que">确定</van-button>
  </div>
</template>

<script>
import { Toast } from 'vant';
export default {
  data() {
    return {
      a: false,
      b: false,
      input1: false,
      zqd_show: true,
      text1:"",
      text2:'',
    };
  },
  created() {},
  mounted() {},
  methods: {
    zqd_que() {
      let res = /^\d\s{3,12}$/
      if(!res.test(this.text1)||!res.test(this.text1)){
        Toast('密码格式不正确')
      }
      if(this.text1==""||this.text2==''){
        Toast('请输入密码')
        return false
      }
      if(this.text1!=this.text2){
        Toast('两次输入的不一样')
        return false
      }
      this.$router.push('/set-message');
    },
  },
};
</script>

<style scoped lang="scss">
.zqd_sp1 {
  color: #808080;
  font-size: 0.14rem;
}
.zqd_div {
  box-sizing: border-box;
  margin: 0 0.6rem;
  border-bottom: 0.01rem solid #808080;
  > input {
    width: 100%;
    height: 1rem;
    border-radius: 0.15rem;
    ::placeholder {
      color: #efefef;
      font-size: 0.14rem;
    }
  }
}
#zqd {
  width: 6.5rem;
  height: 1rem;
  margin-left: 0.5rem;
  margin-top: 5rem;
  border-radius: 0.5rem;
  background: linear-gradient(90deg, #ff9045, #fc5500);
  color: #fff;
  font-size: 0.5rem;
}
.zqd_active {
  border-bottom: 0.01rem solid orange;
}
.van-field__button {
  span {
    color: #eb6100;
    font-size: .32rem;
  }
}
#qq {
  color: #808080;
  font-size: 0.12rem;
  display: inline-block;
}
</style>
